class Solution:
    def maximumSwap(self, num):
        d = list(str(num))
        best = num
        for i in range(len(d)):
            for j in range(i + 1, len(d)):
                d[i], d[j] = d[j], d[i]
                best = max(best, int(''.join(d)))
                d[i], d[j] = d[j], d[i]
        return best

