class Solution:
    def maximumSwap(self, num):
        d = list(str(num))
        n = len(d)
        last = {int(ch): i for i, ch in enumerate(d)}
        for i in range(n):
            for cand in range(9, int(d[i]), -1):
                if last.get(cand, -1) > i:
                    j = last[cand]
                    d[i], d[j] = d[j], d[i]
                    return int(''.join(d))
        return num

