var maximumSwap = function(num) {
    const d = String(num).split('');
    const n = d.length;
    const last = {};
    for (let i = 0; i < n; i++) last[d[i]] = i;
    for (let i = 0; i < n; i++) {
        for (let cand = 9; cand > Number(d[i]); cand--) {
            const j = last[String(cand)];
            if (j !== undefined && j > i) {
                const tmp = d[i]; d[i] = d[j]; d[j] = tmp;
                return Number(d.join(''));
            }
        }
    }
    return num;
};
